		height?: number;
		/** @deprecated Replaced by the "width" property. */
		innerWidth?: number;
		/** @deprecated Replaced by the "height" property. */
		innerHeight?: number;
		url?: string;
		console?: Console;
		settings?: IOptionalBrowserSettings;
	}) {
