							// Clear navigation listeners
							if (frame[PropertySymbol.listeners]) {
								frame[PropertySymbol.listeners].navigation = [];
							}

							resolve();
						})
						.catch((error) => reject(error));
					if (frame.window) {
						frame.window[PropertySymbol.destroy]();
					}
				})
				.catch((error) => reject(error));
		});
	}
